using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void SetUp() => _registry = new ServiceRegistry();

    // -- Dummy service types used by the tests --
    private interface IGreeter { }
    private sealed class Greeter : IGreeter { }
    private interface ILogger { }
    private sealed class Logger : ILogger { }

    // ---- Register + Resolve ----

    [TestMethod]
    public void Resolve_AfterRegister_ReturnsRegisteredInstance()
    {
        var greeter = new Greeter();
        _registry.Register<IGreeter>(greeter);

        var resolved = _registry.Resolve<IGreeter>();

        Assert.AreSame(greeter, resolved);
    }

    [TestMethod]
    public void Resolve_CalledTwice_ReturnsSameInstance()
    {
        _registry.Register<IGreeter>(new Greeter());

        var first = _registry.Resolve<IGreeter>();
        var second = _registry.Resolve<IGreeter>();

        Assert.AreSame(first, second);
    }

    [TestMethod]
    public void Register_CalledTwice_LastRegistrationWins()
    {
        var original = new Greeter();
        var replacement = new Greeter();

        _registry.Register<IGreeter>(original);
        _registry.Register<IGreeter>(replacement);

        Assert.AreSame(replacement, _registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Register_NullService_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() =>
            _registry.Register<IGreeter>(null!));
    }

    // ---- Resolve unregistered ----

    [TestMethod]
    public void Resolve_Unregistered_ReturnsNull()
    {
        Assert.IsNull(_registry.Resolve<IGreeter>());
    }

    // ---- ResolveRequired ----

    [TestMethod]
    public void ResolveRequired_WhenRegistered_ReturnsInstance()
    {
        var greeter = new Greeter();
        _registry.Register<IGreeter>(greeter);

        Assert.AreSame(greeter, _registry.ResolveRequired<IGreeter>());
    }

    [TestMethod]
    public void ResolveRequired_WhenNotRegistered_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() =>
            _registry.ResolveRequired<IGreeter>());
    }

    // ---- Clear ----

    [TestMethod]
    public void Clear_RemovesAllServices()
    {
        _registry.Register<IGreeter>(new Greeter());
        _registry.Register<ILogger>(new Logger());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<IGreeter>());
        Assert.IsNull(_registry.Resolve<ILogger>());
        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    // ---- Remove ----

    [TestMethod]
    public void Remove_RegisteredService_MakesItUnresolvable()
    {
        _registry.Register<IGreeter>(new Greeter());

        _registry.Remove<IGreeter>();

        Assert.IsNull(_registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Remove_OnlyAffectsTargetedService()
    {
        var logger = new Logger();
        _registry.Register<IGreeter>(new Greeter());
        _registry.Register<ILogger>(logger);

        _registry.Remove<IGreeter>();

        Assert.IsNull(_registry.Resolve<IGreeter>());
        Assert.IsNotNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Remove_Unregistered_DoesNotThrow()
    {
        _registry.Remove<IGreeter>(); // should be a no-op
    }

    // ---- GetAll ----

    [TestMethod]
    public void GetAll_ReturnsAllRegisteredServices()
    {
        var greeter = new Greeter();
        var logger = new Logger();
        _registry.Register<IGreeter>(greeter);
        _registry.Register<ILogger>(logger);

        var all = _registry.GetAll();

        Assert.AreEqual(2, all.Count);
        CollectionAssert.Contains((System.Collections.ICollection)all, greeter);
        CollectionAssert.Contains((System.Collections.ICollection)all, logger);
    }
}

